12	// ProviderStatuses is the resolver for the providerStatuses field.
13	// It mirrors the output of `ddx agent providers`, probing each configured
14	// provider for live connectivity and returning their status.
15	func (r *queryResolver) ProviderStatuses(ctx context.Context) ([]*ProviderStatus, error) {
16		svc, err := agent.NewServiceFromWorkDir(r.WorkingDir)
17		if err != nil {
18			// If agent config is missing, return empty list rather than an error.
19			return []*ProviderStatus{}, nil //nolint:nilerr
20		}
21	
22		providers, err := svc.ListProviders(ctx)
23		if err != nil {
24			return nil, fmt.Errorf("listing providers: %w", err)
25		}
26	
27		results := make([]*ProviderStatus, 0, len(providers))
28		for _, p := range providers {
29			url := p.BaseURL
30			if url == "" {
31				url = "(api)"
32			}
33			ps := &ProviderStatus{
34				Name:         p.Name,
35				ProviderType: p.Type,
36				BaseURL:      url,
37				Model:        p.DefaultModel,
38				Status:       p.Status,
39				ModelCount:   p.ModelCount,
40				IsDefault:    p.IsDefault,
41			}
42			if p.CooldownState != nil && !p.CooldownState.Until.IsZero() {
43				s := p.CooldownState.Until.UTC().Format(time.RFC3339)
44				ps.CooldownUntil = &s
45			}
46			results = append(results, ps)
47		}
48	
49		return results, nil
50	}
51	
52	// DefaultRouteStatus is the resolver for the defaultRouteStatus field.
53	// It shows which provider/model the default model-ref resolves to, mirroring
54	// the Visibility 6 route-status data for the default profile.
55	func (r *queryResolver) DefaultRouteStatus(ctx context.Context) (*DefaultRouteStatus, error) {
56		svc, err := agent.NewServiceFromWorkDir(r.WorkingDir)
57		if err != nil {
58			return nil, nil //nolint:nilerr
59		}
60	
61		dec, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{})
62		if err != nil {
63			// No healthy candidate — return empty status rather than an error.
64			return &DefaultRouteStatus{}, nil //nolint:nilerr
65		}
66	
67		result := &DefaultRouteStatus{
68			ModelRef: dec.Model,
69		}
70		if dec.Provider != "" {
71			p := dec.Provider
72			result.ResolvedProvider = &p
73		}
74		if dec.Model != "" {
75			m := dec.Model
76			result.ResolvedModel = &m
77		}
78		return result, nil
79	}
