230	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
231	// querying the service's ListHarnesses and (best-effort) the harness registry.
232	// It is the production replacement for Runner.Capabilities.
233	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
234		if ctx == nil {
235			ctx = context.Background()
236		}
237		svc, err := NewServiceFromWorkDir(workDir)
238		if err != nil {
239			return nil, fmt.Errorf("agent: build service: %w", err)
240		}
241		infos, err := svc.ListHarnesses(ctx)
242		if err != nil {
243			return nil, fmt.Errorf("agent: list harnesses: %w", err)
244		}
245		var info *agentlib.HarnessInfo
246		for i := range infos {
247			if infos[i].Name == harnessName {
248				info = &infos[i]
249				break
250			}
251		}
252		if info == nil {
253			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
254		}
255	
256		// Pull binary and reasoning-level metadata from the local registry — the
257		// service does not expose these directly today.
258		registry := newHarnessRegistry()
259		harness, _ := registry.Get(harnessName)
260	
261		caps := &HarnessCapabilities{
262			Harness:             info.Name,
263			Available:           info.Available,
264			Binary:              harness.Binary,
265			Path:                info.Path,
266			Surface:             harness.Surface,
267			CostClass:           info.CostClass,
268			IsLocal:             info.IsLocal,
269			ExactPinSupport:     info.ExactPinSupport,
270			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
271			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
272		}
273		if len(info.SupportedReasoning) > 0 {
274			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
275		} else if len(harness.ReasoningLevels) > 0 {
276			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
277		}
278	
279		if harness.DefaultModel != "" {
280			caps.Model = harness.DefaultModel
281			caps.Models = []string{harness.DefaultModel}
282		}
283	
284		// Profile mappings come from the local model catalog because the service
285		// does not surface a per-tier resolution endpoint today.
286		if harness.Surface != "" {
287			cat := BuiltinCatalog
288			for _, profile := range []string{"cheap", "fast", "smart"} {
289				if m, ok := cat.Resolve(profile, harness.Surface); ok {
290					if caps.ProfileMappings == nil {
291						caps.ProfileMappings = make(map[string]string)
292					}
293					caps.ProfileMappings[profile] = m
294				}
295			}
296		}
297		return caps, nil
298	}
