300	// TestProviderConnectivityViaService runs a HealthCheck against the named
301	// harness and translates the result into a ProviderStatus. It is the
302	// production replacement for Runner.TestProviderConnectivity.
303	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
304		status := ProviderStatus{Reachable: false}
305		if ctx == nil {
306			ctx = context.Background()
307		}
308		if harnessName == "virtual" || harnessName == "agent" {
309			status.Reachable = true
310			status.CreditsOK = true
311			return status
312		}
313		svc, err := NewServiceFromWorkDir(workDir)
314		if err != nil {
315			status.Error = err.Error()
316			return status
317		}
318		if timeout > 0 {
319			var cancel context.CancelFunc
320			ctx, cancel = context.WithTimeout(ctx, timeout)
321			defer cancel()
322		}
323		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
324			errStr := strings.ToLower(err.Error())
325			status.Error = err.Error()
326			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
327				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
328				status.CreditsOK = false
329			}
330			return status
331		}
332		status.Reachable = true
333		status.CreditsOK = true
334		return status
335	}
