package graphql

// providerStatuses and harnessStatuses together populate the unified
// Agent endpoints surface (bead ddx-23978824, design TD-014).
//
// Both resolvers are **cache-first**: the first-paint path returns either a
// cached snapshot (when one exists) or stub rows (one per configured
// endpoint) immediately, then schedules a background refresh via
// refreshEndpointsCache. This protects the page from synchronous probe-wall
// latency while keeping the CLI's `ddx agent providers` path (which does the
// blocking probe) unchanged.

import (
	"context"
	"fmt"
	"sync"
	"time"

	agentlib "github.com/DocumentDrivenDX/agent"
	"github.com/DocumentDrivenDX/ddx/internal/agent"
)

// endpointsCacheStaleness is the floor below which a cache snapshot is
// considered fresh and no background refresh is scheduled. Short enough that
// an operator polling the page every 2s triggers one refresh and then
// coasts; long enough that 10 browser tabs do not hammer upstream probes.
const endpointsCacheStaleness = 30 * time.Second

// endpointsProbeTimeout bounds a single background refresh.
const endpointsProbeTimeout = 20 * time.Second

// endpointsProbeFn is the function the cache calls to produce a fresh
// snapshot. Defaulting to liveProbe in production; overridden by tests to
// inject deterministic fixtures.
var endpointsProbeFn = liveProbe

type probeResult struct {
	providers []*ProviderStatus
	harnesses []*HarnessStatus
}

type probeSnapshot struct {
	result     probeResult
	capturedAt time.Time
}

type probeCache struct {
	mu         sync.Mutex
	byWorkDir  map[string]*probeSnapshot
	inflight   map[string]*sync.WaitGroup
	lastLaunch map[string]time.Time
}

var globalProbeCache = &probeCache{
	byWorkDir:  make(map[string]*probeSnapshot),
	inflight:   make(map[string]*sync.WaitGroup),
	lastLaunch: make(map[string]time.Time),
}

// get returns the cached snapshot for workDir, or nil if cold.
func (c *probeCache) get(workDir string) *probeSnapshot {
	c.mu.Lock()
	defer c.mu.Unlock()
	return c.byWorkDir[workDir]
}

// set replaces the cached snapshot for workDir.
func (c *probeCache) set(workDir string, r probeResult) {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.byWorkDir[workDir] = &probeSnapshot{result: r, capturedAt: time.Now().UTC()}
}

// shouldLaunch returns true and marks an in-flight probe when the snapshot
// is older than the staleness floor AND no refresh is already running.
// Returns false when a refresh is redundant (fresh) or already in flight.
func (c *probeCache) shouldLaunch(workDir string, snap *probeSnapshot) bool {
	c.mu.Lock()
	defer c.mu.Unlock()
	if _, running := c.inflight[workDir]; running {
		return false
	}
	now := time.Now()
	if snap != nil && now.Sub(snap.capturedAt) < endpointsCacheStaleness {
		// Snapshot is fresh; no refresh needed.
		return false
	}
	// Rate-limit: even if the snapshot says "stale", don't launch more than
	// one refresh per staleness window.
	if last, ok := c.lastLaunch[workDir]; ok && now.Sub(last) < endpointsCacheStaleness {
		return false
	}
	c.inflight[workDir] = &sync.WaitGroup{}
	c.inflight[workDir].Add(1)
	c.lastLaunch[workDir] = now
	return true
}

// markFinished clears the in-flight marker for workDir.
func (c *probeCache) markFinished(workDir string) {
	c.mu.Lock()
	defer c.mu.Unlock()
	if wg, ok := c.inflight[workDir]; ok {
		wg.Done()
		delete(c.inflight, workDir)
	}
}

// waitForInflight blocks until the in-flight probe for workDir (if any)
// completes. Used only by tests that want to synchronize on probe completion.
func (c *probeCache) waitForInflight(workDir string) {
	c.mu.Lock()
	wg := c.inflight[workDir]
	c.mu.Unlock()
	if wg != nil {
		wg.Wait()
	}
}

// ensureSnapshot returns the best available snapshot for workDir, falling
// back to stub rows when the cache is cold. When the snapshot is stale or
// cold a background refresh is scheduled (fire-and-forget).
func ensureSnapshot(ctx context.Context, workDir string) probeResult {
	snap := globalProbeCache.get(workDir)

	if globalProbeCache.shouldLaunch(workDir, snap) {
		// Detach from the request context so the background refresh is not
		// cancelled when the HTTP handler returns.
		go func(wd string) {
			defer globalProbeCache.markFinished(wd)
			probeCtx, cancel := context.WithTimeout(context.Background(), endpointsProbeTimeout)
			defer cancel()
			result := endpointsProbeFn(probeCtx, wd)
			globalProbeCache.set(wd, result)
		}(workDir)
	}

	if snap != nil {
		return snap.result
	}
	// Cache-cold first paint: synthesise stub rows from config so the UI
	// has something to render. Cheap: reads config but does not probe.
	return stubSnapshotFor(workDir)
}

// stubSnapshotFor returns placeholder rows based purely on config (no probes).
// Reachable=false, detail="probing", lastCheckedAt=nil so the UI can render
// a "probing…" indicator that the next poll replaces with real values.
func stubSnapshotFor(workDir string) probeResult {
	res := probeResult{
		providers: []*ProviderStatus{},
		harnesses: []*HarnessStatus{},
	}
	svc, err := agent.NewServiceFromWorkDir(workDir)
	if err != nil || svc == nil {
		return res
	}
	// Use a short-lived context: config-only reads should be immediate,
	// but upstream ListProviders/ListHarnesses may still do light I/O.
	ctx, cancel := context.WithTimeout(context.Background(), 250*time.Millisecond)
	defer cancel()

	providers, _ := svc.ListProviders(ctx)
	for _, p := range providers {
		url := p.BaseURL
		if url == "" {
			url = "(api)"
		}
		ps := &ProviderStatus{
			Name:         p.Name,
			Kind:         "endpoint",
			ProviderType: p.Type,
			BaseURL:      url,
			Model:        p.DefaultModel,
			Status:       "probing",
			ModelCount:   p.ModelCount,
			IsDefault:    p.IsDefault,
		}
		res.providers = append(res.providers, ps)
	}

	harnesses, _ := svc.ListHarnesses(ctx)
	for _, h := range harnesses {
		if h.TestOnly {
			continue
		}
		hs := &HarnessStatus{
			Name:              h.Name,
			Kind:              "harness",
			Reachable:         false,
			Detail:            "probing",
			Path:              h.Path,
			Available:         h.Available,
			CostClass:         h.CostClass,
			DefaultForProfile: []string{},
		}
		res.harnesses = append(res.harnesses, hs)
	}
	return res
}

// liveProbe is the production endpointsProbeFn. It calls ListProviders and
// ListHarnesses (both of which perform live probes inside the upstream
// library) and builds the fully-populated status rows.
func liveProbe(ctx context.Context, workDir string) probeResult {
	res := probeResult{
		providers: []*ProviderStatus{},
		harnesses: []*HarnessStatus{},
	}
	svc, err := agent.NewServiceFromWorkDir(workDir)
	if err != nil || svc == nil {
		return res
	}

	now := time.Now().UTC().Format(time.RFC3339)

	providers, perr := svc.ListProviders(ctx)
	if perr == nil {
		for _, p := range providers {
			url := p.BaseURL
			if url == "" {
				url = "(api)"
			}
			reachable := providerReachable(p.Status)
			checked := now
			ps := &ProviderStatus{
				Name:          p.Name,
				Kind:          "endpoint",
				ProviderType:  p.Type,
				BaseURL:       url,
				Model:         p.DefaultModel,
				Status:        p.Status,
				Reachable:     &reachable,
				ModelCount:    p.ModelCount,
				IsDefault:     p.IsDefault,
				LastCheckedAt: &checked,
				Usage:         nil,
				Quota:         quotaFromAgentLib(p.Quota),
			}
			if p.CooldownState != nil && !p.CooldownState.Until.IsZero() {
				s := p.CooldownState.Until.UTC().Format(time.RFC3339)
				ps.CooldownUntil = &s
			}
			res.providers = append(res.providers, ps)
		}
	}

	harnessInfos, herr := svc.ListHarnesses(ctx)
	if herr == nil {
		defaults := resolveDefaultsByHarness(ctx, svc)
		for _, h := range harnessInfos {
			if h.TestOnly {
				continue
			}
			detail := h.Error
			if detail == "" {
				if h.Available {
					detail = "installed"
				} else {
					detail = "not installed"
				}
			}
			checked := now
			hs := &HarnessStatus{
				Name:              h.Name,
				Kind:              "harness",
				Reachable:         h.Available,
				Detail:            detail,
				Path:              h.Path,
				Available:         h.Available,
				CostClass:         h.CostClass,
				LastCheckedAt:     &checked,
				DefaultForProfile: defaults[h.Name],
				Usage:             nil,
				Quota:             quotaFromAgentLib(h.Quota),
			}
			if hs.DefaultForProfile == nil {
				hs.DefaultForProfile = []string{}
			}
			res.harnesses = append(res.harnesses, hs)
		}
	}

	return res
}

// providerReachable maps the upstream ProviderInfo.Status string to a
// boolean. Anything that contains "connect" or "ok" counts as reachable.
func providerReachable(status string) bool {
	if status == "" {
		return false
	}
	for _, needle := range []string{"connected", "ok", "api key configured", "authenticated"} {
		if containsFold(status, needle) {
			return true
		}
	}
	return false
}

func containsFold(hay, needle string) bool {
	if len(needle) == 0 {
		return true
	}
	if len(hay) < len(needle) {
		return false
	}
	for i := 0; i+len(needle) <= len(hay); i++ {
		match := true
		for j := 0; j < len(needle); j++ {
			hc := hay[i+j]
			nc := needle[j]
			if hc >= 'A' && hc <= 'Z' {
				hc += 'a' - 'A'
			}
			if nc >= 'A' && nc <= 'Z' {
				nc += 'a' - 'A'
			}
			if hc != nc {
				match = false
				break
			}
		}
		if match {
			return true
		}
	}
	return false
}

// resolveDefaultsByHarness walks the canonical profile set and records which
// harness wins routing for each. Errors are swallowed: if a profile cannot
// be resolved we just do not tag any harness with that profile.
func resolveDefaultsByHarness(ctx context.Context, svc agentlib.DdxAgent) map[string][]string {
	defaults := make(map[string][]string)
	for _, profile := range []string{"cheap", "fast", "smart"} {
		dec, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{Profile: profile})
		if err != nil || dec == nil || dec.Harness == "" {
			continue
		}
		defaults[dec.Harness] = append(defaults[dec.Harness], profile)
	}
	return defaults
}

// quotaFromAgentLib translates an upstream QuotaState into the GraphQL
// EndpointQuota. Returns nil when the library did not populate quota.
func quotaFromAgentLib(q *agentlib.QuotaState) *EndpointQuota {
	if q == nil || len(q.Windows) == 0 {
		return nil
	}
	// The upstream library surfaces multiple windows (5h, 7d, etc.). For the
	// row summary we pick the "most pressurised" window — the one with the
	// highest used_percent. The detail route can surface all windows later.
	var worst = q.Windows[0]
	for _, w := range q.Windows[1:] {
		if w.UsedPercent > worst.UsedPercent {
			worst = w
		}
	}

	out := &EndpointQuota{}
	if worst.WindowMinutes > 0 {
		secs := worst.WindowMinutes * 60
		out.CeilingWindowSeconds = &secs
	}
	if worst.UsedPercent != 0 {
		p := worst.UsedPercent
		out.UsedPercent = &p
	}
	if worst.State != "" {
		s := worst.State
		out.State = &s
	}
	if worst.ResetsAt != "" {
		s := worst.ResetsAt
		out.ResetAt = &s
	}
	return out
}

// ProviderStatuses is the resolver for the providerStatuses field. Returns
// the current cached endpoint snapshot (stub rows when cache is cold) and
// schedules a background refresh when the cache is stale.
func (r *queryResolver) ProviderStatuses(ctx context.Context) ([]*ProviderStatus, error) {
	if r.WorkingDir == "" {
		return []*ProviderStatus{}, nil
	}
	snap := ensureSnapshot(ctx, r.WorkingDir)
	if snap.providers == nil {
		return []*ProviderStatus{}, nil
	}
	return snap.providers, nil
}

// HarnessStatuses is the resolver for the harnessStatuses field. Returns
// the current cached harness snapshot (stub rows when cache is cold) and
// schedules a background refresh when the cache is stale.
func (r *queryResolver) HarnessStatuses(ctx context.Context) ([]*HarnessStatus, error) {
	if r.WorkingDir == "" {
		return []*HarnessStatus{}, nil
	}
	snap := ensureSnapshot(ctx, r.WorkingDir)
	if snap.harnesses == nil {
		return []*HarnessStatus{}, nil
	}
	return snap.harnesses, nil
}

// DefaultRouteStatus is the resolver for the defaultRouteStatus field.
// It shows which provider/model the default model-ref resolves to, mirroring
// the Visibility 6 route-status data for the default profile.
func (r *queryResolver) DefaultRouteStatus(ctx context.Context) (*DefaultRouteStatus, error) {
	svc, err := agent.NewServiceFromWorkDir(r.WorkingDir)
	if err != nil {
		return nil, nil //nolint:nilerr
	}

	dec, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{})
	if err != nil {
		// No healthy candidate — return empty status rather than an error.
		return &DefaultRouteStatus{}, nil //nolint:nilerr
	}

	result := &DefaultRouteStatus{
		ModelRef: dec.Model,
	}
	if dec.Provider != "" {
		p := dec.Provider
		result.ResolvedProvider = &p
	}
	if dec.Model != "" {
		m := dec.Model
		result.ResolvedModel = &m
	}
	return result, nil
}

// Fingerprint is imported for the side-effect of keeping fmt in use if the
// package ever loses references to it.
var _ = fmt.Sprint

