package graphql

// Tests for the unified agent-endpoints resolvers (ProviderStatuses,
// HarnessStatuses) backing bead ddx-23978824. These tests exercise the
// cache-first fast-path and the stub snapshot that renders on first paint.

import (
	"context"
	"fmt"
	"sync"
	"sync/atomic"
	"testing"
	"time"
)

// withTestProbe swaps endpointsProbeFn and clears the process cache for the
// duration of a test. It returns a restore function.
func withTestProbe(t *testing.T, fn func(ctx context.Context, workDir string) probeResult) func() {
	t.Helper()
	prev := endpointsProbeFn
	endpointsProbeFn = fn
	globalProbeCache.mu.Lock()
	globalProbeCache.byWorkDir = make(map[string]*probeSnapshot)
	globalProbeCache.inflight = make(map[string]*sync.WaitGroup)
	globalProbeCache.lastLaunch = make(map[string]time.Time)
	globalProbeCache.mu.Unlock()
	return func() {
		endpointsProbeFn = prev
		globalProbeCache.mu.Lock()
		globalProbeCache.byWorkDir = make(map[string]*probeSnapshot)
		globalProbeCache.inflight = make(map[string]*sync.WaitGroup)
		globalProbeCache.lastLaunch = make(map[string]time.Time)
		globalProbeCache.mu.Unlock()
	}
}

func makeResolver(workDir string) *queryResolver {
	r := &Resolver{WorkingDir: workDir}
	return &queryResolver{Resolver: r}
}

// TestProviderStatuses_ReturnsCachedSnapshotImmediately asserts the cache-hit
// fast path: when the cache already has a snapshot for the workDir, a call to
// ProviderStatuses returns the cached rows and does not block on a probe.
func TestProviderStatuses_ReturnsCachedSnapshotImmediately(t *testing.T) {
	t.Parallel()
	workDir := t.TempDir()

	// Seed the cache with a synthesized snapshot.
	reachable := true
	checked := "2026-04-22T10:00:00Z"
	endpoint := &ProviderStatus{
		Name: "seed-endpoint", Kind: "endpoint", ProviderType: "openai-compat",
		BaseURL: "http://seed/v1", Model: "seed-model", Status: "connected",
		Reachable: &reachable, ModelCount: 2, IsDefault: true, LastCheckedAt: &checked,
	}
	harness := &HarnessStatus{
		Name: "seed-harness", Kind: "harness", Reachable: true, Detail: "installed",
		Path: "/usr/bin/seed", Available: true, CostClass: "medium",
		LastCheckedAt: &checked, DefaultForProfile: []string{},
	}
	globalProbeCache.set(workDir, probeResult{
		providers: []*ProviderStatus{endpoint},
		harnesses: []*HarnessStatus{harness},
	})
	t.Cleanup(func() {
		globalProbeCache.mu.Lock()
		delete(globalProbeCache.byWorkDir, workDir)
		delete(globalProbeCache.inflight, workDir)
		delete(globalProbeCache.lastLaunch, workDir)
		globalProbeCache.mu.Unlock()
	})

	// Swap the probe fn so if one fires accidentally, the test notices.
	probed := atomic.Int32{}
	restore := withTestProbe(t, func(ctx context.Context, wd string) probeResult {
		probed.Add(1)
		return probeResult{}
	})
	defer restore()
	// Re-seed because withTestProbe cleared the cache.
	globalProbeCache.set(workDir, probeResult{
		providers: []*ProviderStatus{endpoint},
		harnesses: []*HarnessStatus{harness},
	})

	r := makeResolver(workDir)
	start := time.Now()
	got, err := r.ProviderStatuses(context.Background())
	elapsed := time.Since(start)
	if err != nil {
		t.Fatalf("ProviderStatuses: %v", err)
	}
	if len(got) != 1 || got[0].Name != "seed-endpoint" {
		t.Fatalf("expected seed endpoint row, got %+v", got)
	}
	if elapsed > 50*time.Millisecond {
		t.Fatalf("cache hit should be <50ms, got %v", elapsed)
	}

	gotH, err := r.HarnessStatuses(context.Background())
	if err != nil {
		t.Fatalf("HarnessStatuses: %v", err)
	}
	if len(gotH) != 1 || gotH[0].Name != "seed-harness" {
		t.Fatalf("expected seed harness row, got %+v", gotH)
	}
}

// TestProviderStatuses_ColdCache_SchedulesBackgroundRefresh asserts that a
// cache-cold call returns quickly (stub rows allowed) and kicks off a
// background refresh that populates the cache within a bounded time.
func TestProviderStatuses_ColdCache_SchedulesBackgroundRefresh(t *testing.T) {
	t.Parallel()
	workDir := t.TempDir()

	probed := make(chan struct{}, 1)
	restore := withTestProbe(t, func(ctx context.Context, wd string) probeResult {
		// Simulate a slow probe.
		time.Sleep(200 * time.Millisecond)
		reachable := true
		checked := time.Now().UTC().Format(time.RFC3339)
		res := probeResult{
			providers: []*ProviderStatus{{
				Name: "probed-endpoint", Kind: "endpoint", ProviderType: "anthropic",
				BaseURL: "(api)", Model: "x", Status: "api key configured",
				Reachable: &reachable, ModelCount: 0, IsDefault: true, LastCheckedAt: &checked,
			}},
			harnesses: []*HarnessStatus{{
				Name: "claude", Kind: "harness", Reachable: true, Detail: "installed",
				Path: "/bin/claude", Available: true, CostClass: "medium",
				LastCheckedAt: &checked, DefaultForProfile: []string{"cheap"},
			}},
		}
		select {
		case probed <- struct{}{}:
		default:
		}
		return res
	})
	defer restore()

	r := makeResolver(workDir)

	start := time.Now()
	_, err := r.ProviderStatuses(context.Background())
	firstPaint := time.Since(start)
	if err != nil {
		t.Fatalf("ProviderStatuses: %v", err)
	}
	// First paint must be fast — the synchronous path does not wait for
	// the background probe to finish. 500ms budget matches the bead AC.
	if firstPaint > 500*time.Millisecond {
		t.Fatalf("first paint should be <500ms, got %v", firstPaint)
	}

	// Wait for the background probe to complete.
	select {
	case <-probed:
	case <-time.After(2 * time.Second):
		t.Fatal("background probe never ran")
	}
	globalProbeCache.waitForInflight(workDir)

	// Second call should now return the populated snapshot.
	got, err := r.ProviderStatuses(context.Background())
	if err != nil {
		t.Fatalf("second ProviderStatuses: %v", err)
	}
	if len(got) == 0 || got[0].Name != "probed-endpoint" {
		t.Fatalf("expected probed-endpoint after refresh, got %+v", got)
	}
	if got[0].LastCheckedAt == nil || *got[0].LastCheckedAt == "" {
		t.Fatalf("expected lastCheckedAt populated, got nil")
	}
	if got[0].Reachable == nil || !*got[0].Reachable {
		t.Fatalf("expected reachable=true, got %+v", got[0].Reachable)
	}
	if got[0].Kind != "endpoint" {
		t.Fatalf("expected kind=endpoint, got %q", got[0].Kind)
	}
}

// TestHarnessStatuses_IncludesSubprocessHarnesses asserts that the live probe
// result for harnesses surfaces claude, codex and gemini rows with the right
// shape — specifically that kind=harness and DefaultForProfile is never nil.
func TestHarnessStatuses_IncludesSubprocessHarnesses(t *testing.T) {
	t.Parallel()
	workDir := t.TempDir()

	restore := withTestProbe(t, func(ctx context.Context, wd string) probeResult {
		checked := time.Now().UTC().Format(time.RFC3339)
		mk := func(name, detail string, available bool, profs []string) *HarnessStatus {
			return &HarnessStatus{
				Name: name, Kind: "harness", Reachable: available, Detail: detail,
				Path: fmt.Sprintf("/bin/%s", name), Available: available,
				CostClass: "medium", LastCheckedAt: &checked,
				DefaultForProfile: profs,
			}
		}
		return probeResult{
			harnesses: []*HarnessStatus{
				mk("claude", "installed", true, []string{"smart"}),
				mk("codex", "installed", true, []string{"cheap", "fast"}),
				mk("gemini", "not installed", false, []string{}),
				mk("agent", "installed", true, []string{}),
			},
		}
	})
	defer restore()

	r := makeResolver(workDir)
	// Prime + wait for refresh.
	_, _ = r.HarnessStatuses(context.Background())
	globalProbeCache.waitForInflight(workDir)
	got, err := r.HarnessStatuses(context.Background())
	if err != nil {
		t.Fatalf("HarnessStatuses: %v", err)
	}

	wantNames := map[string]bool{"claude": false, "codex": false, "gemini": false, "agent": false}
	for _, h := range got {
		if _, ok := wantNames[h.Name]; !ok {
			continue
		}
		wantNames[h.Name] = true
		if h.Kind != "harness" {
			t.Errorf("%s kind=%q want harness", h.Name, h.Kind)
		}
		if h.DefaultForProfile == nil {
			t.Errorf("%s DefaultForProfile is nil — must be []string{} at minimum", h.Name)
		}
		if h.LastCheckedAt == nil {
			t.Errorf("%s LastCheckedAt is nil", h.Name)
		}
	}
	for name, seen := range wantNames {
		if !seen {
			t.Errorf("expected harness %q in result, missing", name)
		}
	}
}

// TestEnsureSnapshot_StalenessFloor_CoalescesProbes asserts that a rapid
// burst of queries does not launch multiple concurrent probes — the probe
// cache rate-limits refreshes to one per staleness window.
func TestEnsureSnapshot_StalenessFloor_CoalescesProbes(t *testing.T) {
	t.Parallel()
	workDir := t.TempDir()

	var launches atomic.Int32
	restore := withTestProbe(t, func(ctx context.Context, wd string) probeResult {
		launches.Add(1)
		time.Sleep(150 * time.Millisecond)
		return probeResult{}
	})
	defer restore()

	// Fire 10 back-to-back ensureSnapshot calls.
	var wg sync.WaitGroup
	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			ensureSnapshot(context.Background(), workDir)
		}()
	}
	wg.Wait()
	globalProbeCache.waitForInflight(workDir)

	if n := launches.Load(); n != 1 {
		t.Fatalf("expected exactly 1 probe launch under burst, got %d", n)
	}
}

// TestQuotaFromAgentLib_NilReturnsNil asserts the null-safe conversion.
func TestQuotaFromAgentLib_NilReturnsNil(t *testing.T) {
	t.Parallel()
	if q := quotaFromAgentLib(nil); q != nil {
		t.Fatalf("expected nil when upstream quota is nil, got %+v", q)
	}
}

// TestProviderReachable_MapsStatusStringToBool covers the heuristic used
// when the upstream library returns a Status string rather than a boolean.
func TestProviderReachable_MapsStatusStringToBool(t *testing.T) {
	t.Parallel()
	cases := []struct {
		status string
		want   bool
	}{
		{"connected", true},
		{"Connected (5 models)", true},
		{"API key configured", true},
		{"authenticated", true},
		{"unreachable", false},
		{"error: dial tcp refused", false},
		{"", false},
	}
	for _, tc := range cases {
		if got := providerReachable(tc.status); got != tc.want {
			t.Errorf("providerReachable(%q)=%v want %v", tc.status, got, tc.want)
		}
	}
}

