					body: JSON.stringify({ data: { harnessStatuses: [] } })
				});
			} else {
				await route.fulfill({
					status: 200,
					contentType: 'application/json',
					body: JSON.stringify({ data: { harnessStatuses: [] } })
				});
			}
			return;
		}
		if (body.query.includes('DefaultRouteStatus')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { defaultRouteStatus: DEFAULT_ROUTE } })
			});
			return;
		}
		await route.continue();
	});

	await page.goto(BASE_URL);

	// Initially shows probing status.
	await expect(page.getByText('probing').first()).toBeVisible();

	// Within 5s, the patch should replace it with the real status.
	await expect(page.getByText('api key configured')).toBeVisible({ timeout: 5_000 });
});

